INSERT INTO periods (id, organization_id, framework_id, name, season, description, start_date, end_date, is_current, is_locked, is_visible, snapshot_frozen_at, activated_at, updated_at) VALUES ('952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', '0147d901-984d-44c1-a08f-94f919659596', 'Fall 2025', 'Fall', 'EE 491/492 Fall Poster Presentations', '2025-09-01', '2025-12-20', false, true, true, (timestamp '2025-12-06 09:00:00' - interval '24 hours 0 minutes'), (timestamp '2025-09-01 09:00:00' + interval '53 hours 15 minutes'), (timestamp '2025-12-06 09:00:00' + interval '96 hours 0 minutes')) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('a436fb51-aa71-4afc-a9bf-2232d151fbaa', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 'Evaluates the technical depth of the engineering solution including problem definition, design rationale, and use of appropriate tools.', 30, 30, '#F59E0B', '[{"min":27,"max":30,"label":"Excellent","description":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"min":21,"max":26,"label":"Good","description":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"min":13,"max":20,"label":"Developing","description":"Problem is stated but motivation or technical justification is insufficient."},{"min":0,"max":12,"label":"Insufficient","description":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('8cebf54b-97b4-493c-a837-4707d4828eae', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Communication', 'Written', 'Assesses poster design quality including layout structure, figure labelling, and visual communication of technical results.', 30, 28, '#22C55E', '[{"min":27,"max":30,"label":"Excellent","description":"Poster is visually compelling with logical flow. All figures are high quality and properly labelled."},{"min":21,"max":26,"label":"Good","description":"Layout is clear with only minor visual issues. Most figures are well-labelled."},{"min":13,"max":20,"label":"Developing","description":"Layout has some disorganized sections. Several figures lack labels or captions."},{"min":0,"max":12,"label":"Insufficient","description":"Disorganized poster with missing or low-quality visuals throughout."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('bb41dca1-a7d3-4fa8-a819-cd1d0c92bdf2', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Communication', 'Oral', 'Evaluates oral presentation clarity, pacing, and the ability to respond to technical questions from the jury.', 30, 30, '#3B82F6', '[{"min":27,"max":30,"label":"Excellent","description":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"min":21,"max":26,"label":"Good","description":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"min":13,"max":20,"label":"Developing","description":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"min":0,"max":12,"label":"Insufficient","description":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('ae079c87-3d0a-4aa9-ae5b-8966b4f38a57', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 'Assesses individual contributions, equitable workload distribution, and professional conduct during the evaluation session.', 10, 12, '#EF4444', '[{"min":9,"max":10,"label":"Excellent","description":"Every member demonstrates equal engagement and individual mastery of the project."},{"min":7,"max":8,"label":"Good","description":"Most members contribute actively. Minor gaps in individual depth."},{"min":4,"max":6,"label":"Developing","description":"Contribution is unbalanced. One or two members appear passive."},{"min":0,"max":3,"label":"Insufficient","description":"Single-person dominance. Remaining members show little involvement."}]', 4) ON CONFLICT DO NOTHING;
