INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('684fe08e-8aeb-4069-a864-a800f0e007aa', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Problem Solving & Analysis', 'Problem', 'Evaluates precision of problem formulation, scope definition, constraint identification, and correctness of the analytical approach.', 25, 25, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Problem is precisely formulated with clear scope, constraints, and success metrics."},{"min":17,"max":21,"label":"Good","description":"Problem is well-defined. Minor gaps in constraint handling."},{"min":12,"max":16,"label":"Developing","description":"Problem statement exists but lacks precision."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is vaguely defined with significant logical gaps."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('6ddc3532-8a5c-41f0-a01c-80467a94d895', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'System Design & Architecture', 'Design', 'Assesses architectural soundness, modularity, scalability, and justification of design decisions and component boundaries.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is modular, scalable, and well-justified."},{"min":17,"max":21,"label":"Good","description":"Architecture is sound with clear component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Basic architecture present but modularity concerns not addressed."},{"min":0,"max":11,"label":"Insufficient","description":"No clear architecture."}]', 2) ON CONFLICT DO NOTHING;
