INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('53700e90-0bef-4410-aa0f-3995053ad8a2', '0e963024-a53f-4722-a9e0-5db7a47b4419', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Analytical Thinking', 'Problem', 'Assesses analytical rigor, problem decomposition quality, and identification of constraints and edge cases.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Demonstrates rigorous analytical thinking with precise problem decomposition."},{"min":17,"max":21,"label":"Good","description":"Analysis is mostly thorough with clear problem breakdown."},{"min":12,"max":16,"label":"Developing","description":"Some analytical effort but decomposition is incomplete."},{"min":0,"max":11,"label":"Insufficient","description":"Lacks systematic analytical approach."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('7e8b2e8b-4a9a-4d2c-a87b-955d58d51b03', '0e963024-a53f-4722-a9e0-5db7a47b4419', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Software Architecture', 'Design', 'Evaluates architectural soundness, component modularity, interface design, and scalability considerations.', 25, 25, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Architecture is clean, modular, and well-documented with clear rationale."},{"min":17,"max":21,"label":"Good","description":"Architecture is reasonable with identifiable component boundaries."},{"min":12,"max":16,"label":"Developing","description":"Some structure exists but architectural choices are ad-hoc."},{"min":0,"max":11,"label":"Insufficient","description":"No discernible architecture or design rationale."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('5bab7e88-65ad-43a7-a14f-8b9bbcb9c9af', '0e963024-a53f-4722-a9e0-5db7a47b4419', 'c2a960c2-ec12-409c-a49b-14ac9f66a451', 'implementation_quality', 'Implementation Quality', 'Impl', 'Assesses code quality, testing strategy, continuous integration practices, and documentation completeness.', 20, 20, '#F59E0B', '[{"min":18,"max":20,"label":"Excellent","description":"Code is clean, well-tested, and follows best practices."},{"min":14,"max":17,"label":"Good","description":"Code is readable with adequate test coverage."},{"min":10,"max":13,"label":"Developing","description":"Code works but lacks tests or consistent style."},{"min":0,"max":9,"label":"Insufficient","description":"Code is disorganized, untested, or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('770df56c-9bc9-4108-a5a9-1056b29af922', '0e963024-a53f-4722-a9e0-5db7a47b4419', 'cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'communication', 'Communication & Documentation', 'Comm', 'Evaluates the clarity and completeness of project documentation and the effectiveness of team presentations.', 20, 15, '#EC4899', '[{"min":18,"max":20,"label":"Excellent","description":"Documentation is thorough and developer-friendly."},{"min":14,"max":17,"label":"Good","description":"Documentation covers key areas."},{"min":10,"max":13,"label":"Developing","description":"Documentation exists but is incomplete."},{"min":0,"max":9,"label":"Insufficient","description":"Little to no documentation."}]', 4) ON CONFLICT DO NOTHING;
