INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('9ec0420a-7f95-4e3f-ad37-b95948485c65', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Analytical Thinking', 'Problem', 'Evaluates structured problem decomposition, constraint analysis, and the rigor of the proposed solution approach.', 25, 30, '#EF4444', '[{"min":22,"max":25,"label":"Excellent","description":"Exceptional analytical rigor. Problem is fully decomposed with constraints identified."},{"min":17,"max":21,"label":"Good","description":"Solid analytical approach covering most problem dimensions."},{"min":12,"max":16,"label":"Developing","description":"Analysis is surface-level. Key constraints overlooked."},{"min":0,"max":11,"label":"Insufficient","description":"Problem is treated superficially with no structured thinking."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, description, max_score, weight, color, rubric_bands, sort_order) VALUES ('52f96a98-1ac8-4b6e-aa3c-02ab77905c16', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Software Architecture', 'Design', 'Assesses software architecture quality including component cohesion, interface clarity, and design rationale.', 25, 30, '#3B82F6', '[{"min":22,"max":25,"label":"Excellent","description":"Textbook-quality architecture. Components are cohesive with well-defined interfaces."},{"min":17,"max":21,"label":"Good","description":"Architecture is functional with reasonable separation of concerns."},{"min":12,"max":16,"label":"Developing","description":"Monolithic or poorly factored. Dependencies are tangled."},{"min":0,"max":11,"label":"Insufficient","description":"No coherent architecture. Code organization is arbitrary."}]', 2) ON CONFLICT DO NOTHING;
