INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('93fcb76b-9827-4720-a1a8-9d65fdbc3055', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'FPGA-Based Real-Time Signal Processing for 5G NR', 1, '[{"name":"Kaan Avcı","order":1},{"name":"Levent Dursun","order":2},{"name":"Azra Evren","order":3},{"name":"Gürkan Ateş","order":4},{"name":"Erdem Uzun","order":5}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Implements a pipelined OFDM receiver on a Xilinx Zynq FPGA targeting 3GPP Release 17 numerology. Achieves sub-millisecond latency for channel estimation, equalization, and LDPC decoding with measured throughput exceeding 1.2 Gbps.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46123b99-4f0a-4d61-a870-6ef0f78e371f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Low-Power IoT Sensor Network for Smart Agriculture', 2, '[{"name":"Dilan Aktaş","order":1},{"name":"Tarık Arslan","order":2},{"name":"Elif Yılmaz","order":3},{"name":"Melis Kavak","order":4},{"name":"Arda Keçeci","order":5}]', 'Prof. Turgut Ercan', 'TED University, EE', 'Deploys a LoRaWAN mesh of custom-designed soil-moisture and microclimate sensors across a 2-hectare test field. The STM32-based nodes achieve 18-month battery life through duty-cycled sampling and adaptive transmission intervals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('733f9e70-8f7b-47dc-ad72-a604c760696f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Autonomous Drone Navigation with LiDAR SLAM', 3, '[{"name":"Pelin Aydın","order":1},{"name":"Berk Gündüz","order":2},{"name":"Cenk Duman","order":3},{"name":"Ezgi Doruk","order":4}]', 'Dr. Ece Aydoğan', 'TED University, EE', 'Integrates a Velodyne Puck LiDAR with an NVIDIA Jetson Orin for real-time 3D SLAM on a custom hexacopter. Tested in GPS-denied indoor warehouse environments with obstacle avoidance and path replanning.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('339948a9-b977-4c51-a1bd-c3dab5e32936', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'GaN Power Amplifier Design for Sub-6 GHz 5G', 4, '[{"name":"Sena Yücel","order":1},{"name":"Tuğba Erdem","order":2},{"name":"Aslıhan Coşkun","order":3},{"name":"Elif Naz Balcı","order":4},{"name":"Simge Kalkan","order":5}]', 'Prof. Cengiz Yalın', 'TED University, EE', 'Designs and fabricates a two-stage GaN HEMT power amplifier operating at 3.5 GHz with 42 dBm output power and 68% PAE. Doherty topology enables high linearity under modulated 5G NR signals.') ON CONFLICT DO NOTHING;
