INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f4f0ede3-01c4-46a1-a477-acd42790683e', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Yapay Zeka Destekli Erken Orman Yangını Tespiti', 1, '[{"name":"Arda Keçeci","order":1},{"name":"Yiğit Polat","order":2},{"name":"Candan Yıldız","order":3},{"name":"Alperen Turan","order":4},{"name":"Merve Karaca","order":5}]', 'Dr. Merve Yıldırım', 'Ankara Fen Lisesi', 'Gözetleme kamerası görüntüleri üzerinde duman ve alev tespiti yapan CNN modeli; EfficientNet-B3 omurga ile %96 doğruluk oranında erken uyarı sağlamaktadır. Yanlış alarm oranı güneş parlaması ve sis koşullarında test edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f5c97d0e-9bca-4e0b-a17d-a75193ef0082', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Tarımsal Atıklardan Ağır Metal Filtreleme Membranı', 2, '[{"name":"Rana Keskin","order":1},{"name":"Melis Denizhan","order":2},{"name":"Çağrı Özkan","order":3}]', 'Dr. Merve Yıldırım', 'Ankara Fen Lisesi', 'Pirinç kabuğu ve fındık kabuğu biyokütlesinden sentezlenen aktif karbon membranların kurşun ve kadmiyum iyonlarına karşı adsorpsiyon kapasitesi incelenmiştir. Langmuir izotermi ile 98 mg/g kapasite belirlenmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('836703c7-94e5-4e9c-a1f4-c9aeca526cd1', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Giyilebilir Postür Düzeltme Sensörü ve Mobil Uygulaması', 3, '[{"name":"Batuhan Koçak","order":1},{"name":"Mert Çakır","order":2},{"name":"Ozan Çelebi","order":3}]', 'Dr. Merve Yıldırım', 'Ankara Fen Lisesi', 'MPU6050 ivmeölçer ile sırt eğimini ölçen giyilebilir cihaz; eşik aşımında titreşim geri bildirimi ve günlük postür raporu sunan React Native mobil uygulamasıyla entegre çalışmaktadır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('202b2597-5a44-4ae0-a6a5-4834870f87d0', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Mikroalg Biyoreaktörü ile Atmosferik CO₂ Yakalama', 4, '[{"name":"Berra Yılmaz","order":1},{"name":"Alp Sönmez","order":2},{"name":"Doğan Eren","order":3},{"name":"Nihan Sezer","order":4},{"name":"Mazhar Özdemir","order":5}]', 'Selin Karadeniz', 'İstanbul Atatürk Fen Lisesi', 'Chlorella vulgaris mikroalg kültürü barındıran 10 L fotobiyoreaktör ile atmosferik CO₂ yakalama verimliliği ölçülmüştür. LED aydınlatma spektrumu ve pH optimizasyonu ile günlük 2.3 g/L biyokütle üretimi sağlanmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('585f50bf-9fb8-4d91-a04d-ec0d9d96f763', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Atık Yağlardan Biyodizel Üretim Optimizasyonu', 5, '[{"name":"Umut Şahin","order":1},{"name":"İlayda Başaran","order":2},{"name":"Deniz Ünal","order":3},{"name":"Sevval Kaplan","order":4},{"name":"İrem Demirci","order":5}]', 'Selin Karadeniz', 'İstanbul Atatürk Fen Lisesi', 'Evsel atık kızartma yağlarından bazik katalizör ile transesterifikasyon yöntemiyle biyodizel üretimi. Metanol-yağ oranı, sıcaklık ve katalizör miktarı Taguchi yöntemiyle optimize edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5b69ec00-b61b-4bf1-a938-c4645c26ab9b', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Deprem Erken Uyarı Sensör Ağı Prototipi', 6, '[{"name":"Volkan Demir","order":1},{"name":"Doruk Acar","order":2},{"name":"Caner Turgut","order":3}]', 'Ahmet Çelik', 'İzmir Fen Lisesi', 'MEMS ivmeölçer tabanlı düşük maliyetli sismik sensör düğümleri; P-dalgası algılandığında LoRa ağı üzerinden merkeze uyarı gönderen dağıtık erken uyarı sistemi prototipi.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ec36e04f-bc08-484d-aec8-77976e40ccf2', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Meyve Olgunluk Tespiti için Hiperspektral Görüntüleme', 7, '[{"name":"Sibel Acar","order":1},{"name":"Fatih Tezel","order":2},{"name":"Nur Akdeniz","order":3}]', 'Ahmet Çelik', 'İzmir Fen Lisesi', '400-1000 nm aralığında hiperspektral kamera ile domates olgunluk seviyesinin tahribatsız tespiti. PLS-DA sınıflandırıcı ile dört olgunluk aşaması %93 doğrulukla ayırt edilmiştir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('71359fc5-fa1d-49e0-a508-7791072924f7', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Su Kirliliğinin Yapay Zeka ile İzlenmesi', 8, '[{"name":"Burak Aslan","order":1},{"name":"Emrah Polat","order":2},{"name":"Kutay Erdal","order":3},{"name":"Tolga Erim","order":4},{"name":"Bilge Karakuş","order":5}]', 'Ahmet Çelik', 'İzmir Fen Lisesi', 'Nehir yüzeyinden alınan drone görüntülerinde yağ tabakası ve atık birikimi tespiti yapan segmentasyon modeli. U-Net mimarisi ile piksel bazında %91 IoU değerine ulaşılmıştır.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('29fa0b9f-8d4e-412b-a37c-51b840e6b742', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'Grafen Katkılı Beton Dayanıklılık Analizi', 9, '[{"name":"Baran Tekin","order":1},{"name":"Aslıhan Coşkun","order":2},{"name":"Fulya Kozan","order":3}]', 'Dr. Burcu Eren', 'ODTÜ GV Lisesi', 'Çimento karışımına farklı oranlarda grafen oksit eklenerek basınç dayanımı, eğilme mukavemeti ve su geçirgenliği testleri yapılmıştır. %0.05 katkı oranında basınç dayanımı %28 artmıştır.') ON CONFLICT DO NOTHING;
