INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32f1ec66-89dc-49f5-a867-7ec816ff6d07', '6c44b363-4522-4cad-a251-06484b72b164', 'Metamaterial Absorber for Radar Cross-Section Reduction', 4, '[{"name":"Aria Sanders","order":1},{"name":"Violet Keane","order":2},{"name":"Willow Drake","order":3},{"name":"Noah Patterson","order":4}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A polarization-insensitive metamaterial absorber using resistively loaded split-ring resonators, achieving greater than 90% absorption from 8 to 12 GHz for RCS reduction applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('5e784ee9-8ce7-4cae-a580-a07a1f11b557', '6c44b363-4522-4cad-a251-06484b72b164', 'Reconfigurable Metasurface for Beam Steering', 5, '[{"name":"Keira Stanton","order":1},{"name":"Thatcher Lyle","order":2},{"name":"Corbin Wolfe","order":3},{"name":"Elise Whitfield","order":4}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A 1-bit reconfigurable intelligent surface with PIN-diode-switched unit cells at 5.8 GHz, electronically steering a reflected beam over ±60° with measured 1.5 dB scanning loss.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('acb58410-579f-4a67-a462-68dfd1beec2e', '6c44b363-4522-4cad-a251-06484b72b164', 'Textile-Integrated Antenna Array for Body Area Networks', 6, '[{"name":"Eleanor Marsh","order":1},{"name":"Vincent Crane","order":2},{"name":"Julian Hayes","order":3},{"name":"Nora Kingsley","order":4},{"name":"Maya Jenkins","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A two-element conductive-thread antenna array embroidered into a polyester sports shirt, operating at 2.45 GHz for WBAN with -15 dB mutual coupling despite close inter-element spacing.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32635f22-7ece-4fe8-a2e5-a0596659e09a', '6c44b363-4522-4cad-a251-06484b72b164', 'Frequency-Tunable Slot Antenna Using Varactor Diodes', 7, '[{"name":"Willa Prescott","order":1},{"name":"Neve Cassidy","order":2},{"name":"Aurora Price","order":3},{"name":"Celia Graves","order":4},{"name":"Iris Mercer","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A CPW-fed slot antenna whose resonant frequency tunes continuously from 2.2 to 3.8 GHz via reverse-biased varactor loading, covering LTE bands 1 through 7 with a single aperture.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('07acad75-3870-4cca-a9e6-90ebcae9aa69', '6c44b363-4522-4cad-a251-06484b72b164', 'SIW-Based Diplexer for TX-RX Systems', 8, '[{"name":"Mason Bell","order":1},{"name":"Leo Gallagher","order":2},{"name":"Felix Palmer","order":3},{"name":"Amelia Wright","order":4}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A substrate-integrated-waveguide diplexer at 24/28 GHz for full-duplex mmWave front-ends, fabricated on a single Rogers 5880 layer with better than 35 dB TX-RX isolation.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ee36879d-c1a0-4042-ae3d-4785e41a000b', '6c44b363-4522-4cad-a251-06484b72b164', 'Millimeter-Wave Lens Antenna for Automotive Radar', 9, '[{"name":"Elias Boyd","order":1},{"name":"Esme Darling","order":2},{"name":"Wyatt Watson","order":3},{"name":"Lydia Campion","order":4}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A 3D-printed dielectric lens with gradient-index profile illuminated by an open-ended waveguide at 77 GHz, producing a 3° pencil beam with 28 dBi gain for long-range automotive radar.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('40a4601a-bd4f-420e-ad80-b3567e6178b3', '6c44b363-4522-4cad-a251-06484b72b164', 'Fractal Antenna for Ultra-Wideband Applications', 10, '[{"name":"Graham Henley","order":1},{"name":"Penelope Blake","order":2},{"name":"Abigail Reeves","order":3},{"name":"Lily Cooper","order":4}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A Minkowski-island fractal monopole printed on FR-4, covering 3.1 to 10.6 GHz with VSWR below 2:1 and a compact footprint 40% smaller than a conventional UWB disc monopole.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('558f6b14-f11f-4dc3-ad37-c9041ad4e145', '318124ea-8614-4355-ad48-2486524dfc13', 'Reconfigurable FSS for 5G Shielding', 1, '[{"name":"Stella Myers","order":1},{"name":"Julian Hayes","order":2},{"name":"Rhys Davenport","order":3},{"name":"Celeste Whitmore","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A frequency-selective surface with PIN-diode-switchable unit cells that toggles between pass and stop states at 3.5 GHz, enabling on-demand electromagnetic shielding for secure rooms.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e970c78e-aaff-43ef-a236-77caf54b07ce', '318124ea-8614-4355-ad48-2486524dfc13', 'Compact MIMO Antenna for Sub-6 GHz Handsets', 2, '[{"name":"Landon Howe","order":1},{"name":"Ryan Price","order":2},{"name":"Layla Stone","order":3},{"name":"Chloe Ward","order":4},{"name":"Mia Howard","order":5}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A four-port MIMO antenna occupying 150x75 mm using orthogonal slot modes to achieve ECC below 0.05 across 3.3-3.8 GHz for 5G smartphone integration.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9c450cf6-cae4-4390-a3ed-12f231962d02', '318124ea-8614-4355-ad48-2486524dfc13', 'SIW Filter for Ka-Band', 3, '[{"name":"Hazel Foster","order":1},{"name":"Dylan Reed","order":2},{"name":"Maya Jenkins","order":3},{"name":"Eva Harding","order":4},{"name":"Aria Sanders","order":5}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A fourth-order Chebyshev bandpass filter implemented in SIW at 26 GHz with 800 MHz bandwidth, 1.2 dB insertion loss, and 25 dB rejection at ±1.5 GHz offset.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('985b9ce9-1302-4ed5-ac37-74f7c3eebfc5', '318124ea-8614-4355-ad48-2486524dfc13', 'Broadband Log-Periodic for EMC Testing', 4, '[{"name":"Eleanor Marsh","order":1},{"name":"Sophie Clarke","order":2},{"name":"Lucy Brooks","order":3}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A printed log-periodic dipole array covering 200 MHz to 6 GHz for pre-compliance EMC measurements, with calibrated gain data traceable to a reference horn antenna.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('cd611107-acdf-40c5-ade3-321c5d20b22b', '318124ea-8614-4355-ad48-2486524dfc13', 'MIMO Antenna for Wi-Fi 6E Access Points', 5, '[{"name":"Calder Shaw","order":1},{"name":"Ella Brooks","order":2},{"name":"Charlotte Kim","order":3},{"name":"Olivia Chen","order":4},{"name":"Patrick Rowe","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'An eight-port ceiling-mount MIMO antenna covering 5.925-7.125 GHz (Wi-Fi 6E) with dual-polarized patch elements and port-to-port isolation exceeding 22 dB.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('fc0404be-5d8b-4521-a139-40d70ba3fcc4', '318124ea-8614-4355-ad48-2486524dfc13', 'Circularly Polarized Horn for Satellite Comm', 6, '[{"name":"Pierce Dalton","order":1},{"name":"Elias Boyd","order":2},{"name":"Leo Gallagher","order":3},{"name":"Lydia Campion","order":4},{"name":"Willa Prescott","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A corrugated conical horn antenna with septum polarizer producing RHCP at Ku-band (12.5 GHz) with 0.5 dB axial ratio and 20 dBi gain for VSAT ground terminals.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('84581ca4-8e1a-4cc6-a71b-2f34be4c1a82', '318124ea-8614-4355-ad48-2486524dfc13', 'Implantable Antenna for Deep Tissue Biotelemetry', 7, '[{"name":"Conrad Wells","order":1},{"name":"Scarlett Wood","order":2},{"name":"Sophia Linden","order":3},{"name":"Isla Webb","order":4}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A miniaturized PIFA operating in the MedRadio band (401-406 MHz) encapsulated in biocompatible silicone, with link-budget analysis for 10 mm implant depth in muscle tissue.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('0527c7f7-28f0-4560-aaf3-1118d5f48d63', '318124ea-8614-4355-ad48-2486524dfc13', 'Dual-Polarized Base Station Antenna', 8, '[{"name":"Sienna West","order":1},{"name":"Callum Harding","order":2},{"name":"Clara Dawson","order":3},{"name":"Noah Patterson","order":4}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A wideband dual-polarized cross-dipole antenna element for macro base stations covering 1.7-2.7 GHz with ±45° slant polarization, 65° HPBW, and 17 dBi gain.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('55964658-c936-45e8-ae7c-bccdb9dcfb20', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Dielectric Resonator Antenna for mmWave Imaging', 1, '[{"name":"Tristan Blake","order":1},{"name":"Tessa Marlow","order":2},{"name":"Graham Henley","order":3},{"name":"Keira Stanton","order":4}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A cylindrical dielectric resonator antenna excited in the HEM11 mode at 60 GHz, achieving 12 dBi gain and 18% impedance bandwidth for short-range imaging applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bc3fe67d-937f-4744-ae90-a19293fc5d5c', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Flexible Inkjet-Printed Antenna for Wearable IoT', 2, '[{"name":"Brynn Ellery","order":1},{"name":"Nora Kingsley","order":2},{"name":"Matthew Doyle","order":3},{"name":"Caleb Richardson","order":4},{"name":"Tatum Pierce","order":5}]', 'Prof. Harold Kim', 'U. Michigan, ECE', 'A silver-nanoparticle inkjet-printed meander-line antenna on PET film, resonating at 2.45 GHz with -12 dBi gain, surviving 500 bend cycles to a 15 mm radius.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e819a48d-0cd4-4027-aa05-4c5458518283', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Patch Antenna Array for 24 GHz Doppler Radar', 3, '[{"name":"Conrad Wells","order":1},{"name":"Ruby Murphy","order":2},{"name":"Henry Torres","order":3}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A 2x4 series-fed patch array on Rogers 5880 for K-band CW Doppler radar, providing 18 dBi gain with a fan beam for traffic speed measurement.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ab1fc3ab-1121-4eac-a869-537be94d5d4f', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Wearable Antenna for UHF Emergency Comm', 4, '[{"name":"Jack Kelly","order":1},{"name":"Cedric Rush","order":2},{"name":"Willa Prescott","order":3},{"name":"Jasper Voss","order":4}]', 'Dr. Sarah Novak', 'Georgia Tech, ECE', 'A flexible inverted-F antenna integrated into a firefighter jacket collar, operating at 430 MHz with ground-plane independence verified through on-body measurements.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('48863d9f-885f-4f71-a929-d3313626b41b', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Compact Loop Antenna for NFC/WPT', 5, '[{"name":"Daniel Frost","order":1},{"name":"Elias Boyd","order":2},{"name":"Ella Brooks","order":3},{"name":"Hazel Foster","order":4},{"name":"Aurora Price","order":5}]', 'Prof. Wei Zhang', 'UCLA, EE', 'A planar spiral-loop antenna at 13.56 MHz optimized for simultaneous NFC data transfer and 2W wireless power transfer to wearable medical devices.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('dcfe3392-61a2-44e1-ae05-da975e5f46a2', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'Printed Yagi-Uda for Direction Finding', 6, '[{"name":"Astrid Lyons","order":1},{"name":"Brielle Osborn","order":2},{"name":"Wren Ellsworth","order":3}]', 'Dr. Anita Patel', 'Purdue, ECE', 'A five-element printed Yagi-Uda at 900 MHz with 9 dBi gain and 50° HPBW, used as the element in a four-quadrant DF array for wildlife VHF collar tracking.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7409c3d5-b62b-487e-aa60-8be8b736f7d9', '47979751-163d-48b3-ae56-a65586d18f1b', 'Autogyro Descent and Precision Landing System', 1, '[{"name":"Graham Henley","order":1},{"name":"Andrew Holden","order":2},{"name":"Mia Howard","order":3},{"name":"Nolan Davies","order":4},{"name":"Dylan Reed","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Replaces the traditional parachute with a folding autogyro rotor blade assembly that deploys at apogee. Achieves a controlled 5 m/s descent rate with GPS-guided heading corrections targeting a 10 m landing circle.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d812e821-9cf5-4042-ae7b-7b45b9a7b922', '47979751-163d-48b3-ae56-a65586d18f1b', 'Dual-Redundant Telemetry with LoRa Failover', 2, '[{"name":"Sterling Cain","order":1},{"name":"Piper York","order":2},{"name":"Lucy Brooks","order":3},{"name":"Victoria Hale","order":4},{"name":"Isaac Perez","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Primary telemetry uses 915 MHz FSK at 19.2 kbps; a secondary LoRa channel activates automatically if packet loss exceeds 20%, ensuring continuous data downlink throughout the 600 m descent.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e3603c93-8069-4824-afa0-10fe733475e3', '47979751-163d-48b3-ae56-a65586d18f1b', 'Multi-Sensor Atmospheric Profiling Payload', 3, '[{"name":"Faye Alderman","order":1},{"name":"Rhys Davenport","order":2},{"name":"Davis Carver","order":3},{"name":"Merrick Towne","order":4},{"name":"Vaughn Kelley","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Carries BME680, SCD41, and UV-B sensors to build a vertical atmospheric profile of temperature, humidity, CO₂, and UV irradiance from 700 m AGL to ground, sampled at 10 Hz.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('851c3941-dfa8-4feb-ae26-c58965626732', '47979751-163d-48b3-ae56-a65586d18f1b', 'Deployable Aerobrake Heat Shield Demonstrator', 4, '[{"name":"Porter Haines","order":1},{"name":"Connor Ross","order":2},{"name":"Declan Holt","order":3},{"name":"Cole Harrison","order":4},{"name":"Daniel Frost","order":5}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'A spring-loaded deployable drag device made from Nomex fabric and carbon-fiber ribs, demonstrating controlled deceleration from 30 m/s to 8 m/s within the first 200 m of descent.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d4678ba7-7203-4cca-a7c5-d1f4fca3908e', '47979751-163d-48b3-ae56-a65586d18f1b', 'Split-Body CanSat with Wireless Inter-Module Telemetry', 5, '[{"name":"Dahlia Novak","order":1},{"name":"Penelope Blake","order":2},{"name":"Gabriel Locke","order":3}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'The CanSat separates at apogee into a sensor pod and a gliding recovery vehicle, communicating via a 2.4 GHz radio link. Both modules transmit independent telemetry to the ground station.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('0b4d032f-9552-4644-a0e2-3efe9c7f3f68', '47979751-163d-48b3-ae56-a65586d18f1b', 'GNSS-Denied Navigation Using Barometric-IMU Fusion', 6, '[{"name":"Odette Marsh","order":1},{"name":"Oscar Quinn","order":2},{"name":"Ella Brooks","order":3},{"name":"Lucas Sullivan","order":4}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Demonstrates position estimation during simulated GPS jamming by fusing barometric altitude, 9-DOF IMU data, and a terrain-referenced navigation algorithm with 15 m CEP accuracy.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('b028da5a-0017-4799-a2c7-27d29ed1687e', '47979751-163d-48b3-ae56-a65586d18f1b', 'Thermal Imaging Mission for Wildfire Detection', 7, '[{"name":"Ada Carrington","order":1},{"name":"Celia Graves","order":2},{"name":"Darcy Irvine","order":3},{"name":"Keira Stanton","order":4}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Mounts a FLIR Lepton 3.5 thermal camera to detect ground hotspots during descent, processing thermal frames on an RP2040 to flag anomalies and geotag them with concurrent GPS fixes.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('31c6101a-8ca5-468e-a298-f559a3b3dbfa', '47979751-163d-48b3-ae56-a65586d18f1b', 'Controlled Descent Using Active Fin Steering', 8, '[{"name":"Sophie Clarke","order":1},{"name":"Jasper Voss","order":2},{"name":"Emma Peterson","order":3},{"name":"Eleanor Marsh","order":4},{"name":"Matthew Doyle","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Four servo-actuated fins provide roll and pitch control during parachute descent, guided by a PID controller tracking GPS waypoints to steer the CanSat toward a designated landing zone.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('d40b8b02-6cb2-4d55-a234-e30758141de2', '47979751-163d-48b3-ae56-a65586d18f1b', 'Radiation Dosimetry for High-Altitude Profiling', 9, '[{"name":"Tessa Rowan","order":1},{"name":"Benjamin Cruz","order":2},{"name":"Barrett Fox","order":3},{"name":"Brooks Aldridge","order":4}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'A Geiger-Muller tube and SiPM-based scintillator measure ionizing radiation dose rate from launch to landing, building a vertical dose profile relevant to aviation and balloon missions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f020fcf5-946a-46b8-a84f-c5f04cb7b58f', '47979751-163d-48b3-ae56-a65586d18f1b', 'AI-Powered Image Classification During Descent', 10, '[{"name":"Astrid Lyons","order":1},{"name":"Avery James","order":2},{"name":"Owen Gray","order":3}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'A downward-facing camera captures terrain images during descent, classified on-board by a TensorFlow Lite model into land-cover categories (vegetation, water, urban, bare soil) and transmitted in real time.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bfe219aa-e626-4093-acb4-0a8d92229438', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Parafoil Guided Recovery with GPS Waypoints', 1, '[{"name":"Jack Kelly","order":1},{"name":"Avery James","order":2},{"name":"Patrick Rowe","order":3}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'A ram-air parafoil with servo-controlled brake toggles guides the CanSat through four GPS waypoints during descent, achieving a 25 m landing accuracy in field tests.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('667b7df9-720b-44ea-a5c0-47ee35ca31b7', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Solar-Powered Secondary Mission: UV Index Mapping', 2, '[{"name":"Ellis Greer","order":1},{"name":"Logan Bailey","order":2},{"name":"Henry Torres","order":3},{"name":"Maya Jenkins","order":4},{"name":"Isaac Perez","order":5}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'Thin-film solar cells supplement the battery during descent while a VEML6075 UV sensor maps UV-A and UV-B intensity at 5 m altitude increments for atmospheric research.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('77459bde-2dda-4848-a5c5-22decb273d5e', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Deployable Boom Magnetometer Suite', 3, '[{"name":"Finley Archer","order":1},{"name":"Selene Ashford","order":2},{"name":"Sienna West","order":3}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'A 30 cm spring-loaded boom extends after ejection to distance a fluxgate magnetometer from the CanSat electronics, measuring geomagnetic field variation with 10 nT resolution.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('773e8005-abb3-4115-aa62-224c65426bd5', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Hydrogen Fuel Cell Ground Recovery Vehicle', 4, '[{"name":"Naomi Swift","order":1},{"name":"Keira Stanton","order":2},{"name":"Daniel Frost","order":3},{"name":"Theodore Grant","order":4}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'A PEM fuel-cell-powered rover navigates to the CanSat landing coordinates using GPS, retrieves the payload, and returns to the launch site autonomously.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('3306ba65-62d0-4044-a435-d9f457938b61', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Dual-Camera Stereoscopic Terrain Mapping', 5, '[{"name":"Dylan Reed","order":1},{"name":"Mabel Trent","order":2},{"name":"Emmett Lawson","order":3}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Two synchronized OV5640 cameras capture stereo image pairs during descent, processed on the ground into a 3D point cloud for terrain reconstruction of the landing area.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('566b1cba-0607-4bc3-ab75-001d836f52fd', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'CanSat-to-CanSat Mesh Communication', 6, '[{"name":"Jasper Voss","order":1},{"name":"Piper York","order":2},{"name":"Sophia Linden","order":3},{"name":"Chloe Ward","order":4},{"name":"Elias Boyd","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'Two CanSats launched in sequence form a 900 MHz mesh relay, extending telemetry range by 60% and demonstrating multi-node swarm communication for future missions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('8e77b600-33f8-4c60-ab99-8877d4b5e3cb', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Biodegradable Structure CanSat Design', 7, '[{"name":"Nolan Davies","order":1},{"name":"Colton Sawyer","order":2},{"name":"Silas Hartley","order":3}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'The airframe is constructed from PLA and mycelium composite panels that fully biodegrade within 90 days, addressing environmental concerns for CanSats that cannot be recovered.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('497d7e77-85d4-4805-a55d-14f26b24df0a', '10abd4e8-0cb9-4853-a17c-ac40da311bff', 'Acoustic Wind Profiling Payload', 8, '[{"name":"Sterling Cain","order":1},{"name":"Penelope Blake","order":2},{"name":"Lucy Brooks","order":3},{"name":"Tessa Rowan","order":4},{"name":"Connor Ross","order":5}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'Four MEMS microphones arranged in a tetrahedral array measure wind speed and direction during descent via time-of-arrival acoustic anemometry, providing 1 Hz wind profiles.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('8b01cc7c-13ab-422f-adc9-8a0a796c8dc4', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Maple-Seed Inspired Passive Descent Vehicle', 1, '[{"name":"Gabriel Locke","order":1},{"name":"Winona Steele","order":2},{"name":"Dahlia Novak","order":3},{"name":"Quinn Radley","order":4}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'A single-blade autorotation design inspired by maple samaras achieves a stable 4 m/s descent without active control, with the spin rate providing attitude stabilization.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('15713af0-a06b-43ac-a10b-867a682f2409', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Ground Station with Real-Time 3D Trajectory', 2, '[{"name":"Calder Shaw","order":1},{"name":"Violet Keane","order":2},{"name":"Dylan Reed","order":3},{"name":"Zoe Powell","order":4}]', 'Prof. Richard Kline', 'Virginia Tech, Aerospace', 'A Python/Qt ground station application receives 10 Hz telemetry and renders the CanSat trajectory in a 3D map view with altitude, velocity, and orientation overlays.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('71ed11c1-d2ae-4664-a535-f668a29adab5', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Glider Recovery with Autonomous Steering', 3, '[{"name":"Odette Marsh","order":1},{"name":"Rhys Davenport","order":2},{"name":"Merrick Towne","order":3}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'The CanSat transitions to a fixed-wing glider configuration after parachute release, autonomously steering toward the launch site using proportional navigation guidance.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('25395f4a-1f2c-4990-a5c8-653c43148c99', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'LoRa Long-Range Telemetry Ground Station', 4, '[{"name":"Harlow Sinclair","order":1},{"name":"Eva Harding","order":2},{"name":"Adam Bennett","order":3}]', 'Dr. Samantha Ford', 'MIT, AeroAstro', 'A high-gain Yagi antenna and LoRa receiver achieve reliable telemetry reception at 8 km range using spreading factor 10 at 868 MHz with forward error correction.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e4f166c7-899d-4b1c-a809-f2cc2ff6de1a', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Atmospheric Particulate Matter Sampling', 5, '[{"name":"Elodie Kincaid","order":1},{"name":"Junia Phelps","order":2},{"name":"Ellis Greer","order":3},{"name":"Hayes Drummond","order":4},{"name":"Tessa Marlow","order":5}]', 'Prof. Douglas Park', 'CU Boulder, Aerospace', 'A miniature impactor sampler collects PM2.5 and PM10 particles on adhesive substrate during descent, analyzed post-flight under a microscope for morphology and composition.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('936c6454-b5ce-426c-ab65-292bd991fa1f', '9f49cd18-d850-4b1e-ae53-c08253910f4e', 'Parachute Deployment Optimization via ML', 6, '[{"name":"Conrad Wells","order":1},{"name":"Brooks Aldridge","order":2},{"name":"Maeve Alcott","order":3}]', 'Dr. Yuki Tanaka', 'Caltech, GALCIT', 'A random-forest model trained on 200 simulation runs predicts optimal parachute deployment altitude based on real-time wind and descent-rate data, minimizing landing dispersion.') ON CONFLICT DO NOTHING;
