INSERT INTO jury_feedback (period_id, juror_id, rating, comment, is_public, created_at) VALUES
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 4, NULL, false, (timestamp '2026-06-01 09:00:00' + interval '13 hours 33 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '9a21397b-552a-4b00-a5c4-15a0982436b1', 5, 'Very practical system. We completed all evaluations on poster day without any issues.', true, (timestamp '2026-06-01 09:00:00' + interval '4 hours 54 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '868057b9-f2e0-4db1-a4e9-e258d25f84e1', 4, 'Clean interface with fast response. The rubric bands were extremely helpful.', true, (timestamp '2026-06-01 09:00:00' + interval '14 hours 7 minutes')),
('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '56948fec-ce3d-493b-afc4-4e281e9b8f58', 3, 'Decent tool overall, but the mobile layout could use improvement for tablet users.', true, (timestamp '2026-06-01 09:00:00' + interval '4 hours 58 minutes')),
('952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'aaa0da50-6432-47e0-ab48-b01ca823ef19', 5, NULL, false, (timestamp '2025-12-06 09:00:00' + interval '15 hours 14 minutes')),
('952dd05e-8ff2-44a7-a13b-9a22958f57fb', '7d1bbec7-493f-4e1a-aee5-be30df51db49', 4, 'Gets better every semester.', true, (timestamp '2025-12-06 09:00:00' + interval '15 hours 20 minutes')),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '47dcf645-bcf8-407e-a86e-f0e506495726', 5, 'Replaced our old paper-based system entirely. The export feature saves hours.', true, (timestamp '2026-06-01 09:00:00' + interval '5 hours 3 minutes')),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '44e14170-d567-4ad4-a771-cd269d538a2f', 4, 'Solid tool. Configurable criteria made it easy to adapt.', true, (timestamp '2026-06-01 09:00:00' + interval '9 hours 7 minutes')),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'cdfec676-c0dc-4c35-a5d8-79ba609e397d', 5, 'Clean and intuitive. Scoring 12 projects took less than an hour.', true, (timestamp '2026-06-01 09:00:00' + interval '16 hours 53 minutes')),
('e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '4880a479-e7ba-47bd-a66d-7b889755d7c0', 2, 'Had connectivity issues during the session. Lost some progress before it autosaved.', false, (timestamp '2026-06-01 09:00:00' + interval '6 hours 58 minutes')),
('b90e1112-88c7-44fa-a275-25bc0ad2d96d', '47dcf645-bcf8-407e-a86e-f0e506495726', 5, NULL, false, (timestamp '2025-12-06 09:00:00' + interval '24 hours 41 minutes')),
('b90e1112-88c7-44fa-a275-25bc0ad2d96d', '44e14170-d567-4ad4-a771-cd269d538a2f', 3, NULL, false, (timestamp '2025-12-06 09:00:00' + interval '2 hours 46 minutes')),
('0e963024-a53f-4722-a9e0-5db7a47b4419', '47dcf645-bcf8-407e-a86e-f0e506495726', 4, NULL, false, (timestamp '2025-06-01 09:00:00' + interval '18 hours 34 minutes')),
('0e963024-a53f-4722-a9e0-5db7a47b4419', '44e14170-d567-4ad4-a771-cd269d538a2f', 5, 'Third semester using VERA. It keeps getting better.', true, (timestamp '2025-06-01 09:00:00' + interval '24 hours 53 minutes')),
('e77bf882-fc32-461c-acab-6ee1696df0c7', 'cec22180-51e9-4924-a2d0-6bca4aeb0028', 5, 'Yüzlerce takımı hızlıca değerlendirdik. Sistem çok stabil.', true, (timestamp '2026-07-25 09:00:00' + interval '13 hours 59 minutes')),
('e77bf882-fc32-461c-acab-6ee1696df0c7', '618aec67-dbed-41bf-ac48-c600f70c9fa5', 4, 'Yarışma ortamında çok pratik. QR ile giriş mükemmel.', true, (timestamp '2026-07-25 09:00:00' + interval '41 hours 22 minutes')),
('e77bf882-fc32-461c-acab-6ee1696df0c7', 'e4550b83-b849-4977-a7b0-dc011fad64f5', 3, 'Kullanılabilir ama yarışma günü internet kesintisinde sorun yaşadık.', false, (timestamp '2026-07-25 09:00:00' + interval '33 hours 26 minutes')),
